def train_agent(num_disks: int = 3, episodes: int = 5000, verbose: bool = True,
                learning_rate: float = 0.1, discount_factor: float = 0.95,
                epsilon_decay: float = 0.9995) -> QLearningAgent:
    """
    Train Q-learning agent to solve Tower of Hanoi.
    
    Args:
        num_disks: Number of disks
        episodes: Number of training episodes
        verbose: Whether to print progress
        learning_rate: Learning rate for Q-learning
        discount_factor: Discount factor for future rewards
        epsilon_decay: Decay rate for exploration
        
    Returns:
        Trained agent
    """
    env = HanoiTower(num_disks)
    agent = QLearningAgent(learning_rate=learning_rate, 
                          discount_factor=discount_factor,
                          epsilon_decay=epsilon_decay)
    
    rewards_history = []
    moves_history = []
    success_rate = []
    
    start_time = time.time()
    
    for episode in range(episodes):
        state = env.reset()
        total_reward = 0
        done = False
        max_steps = 1000  # Allow more steps for complex problems
        steps = 0
        
        while not done and steps < max_steps:
            valid_actions = env.get_valid_actions()
            action = agent.get_action(state, valid_actions)
            next_state, reward, done, _ = env.step(action)
            next_valid_actions = env.get_valid_actions()
            
            agent.update(state, action, reward, next_state, next_valid_actions, done)
            
            state = next_state
            total_reward += reward
            steps += 1
        
        agent.decay_epsilon()
        rewards_history.append(total_reward)
        moves_history.append(env.moves)
        
        # Calculate success rate over last 100 episodes
        if episode >= 99:
            recent_success = sum(1 for i in range(episode-99, episode+1) 
                               if rewards_history[i] > 0)
            success_rate.append(recent_success / 100)
        
        # Print progress
        if verbose and (episode + 1) % 500 == 0:
            elapsed = time.time() - start_time
            avg_reward = np.mean(rewards_history[-500:])
            avg_moves = np.mean(moves_history[-500:])
            current_success = success_rate[-1] if success_rate else 0
            print(f"Episode {episode + 1}/{episodes} | Time: {elapsed:.1f}s")
            print(f"  Avg Reward: {avg_reward:.2f}")
            print(f"  Avg Moves: {avg_moves:.2f}")
            print(f"  Success Rate: {current_success:.2%}")
            print(f"  Epsilon: {agent.epsilon:.4f}")
    
    training_time = time.time() - start_time
    
    if verbose:
        optimal_moves = 2**num_disks - 1
        print(f"\nTraining completed in {training_time:.2f} seconds ({training_time/60:.2f} minutes)")
        print(f"Optimal solution requires {optimal_moves} moves")
    
    return agent


def train_dqn_agent(num_disks: int = 5, episodes: int = 10000, 
                    target_update: int = 100, verbose: bool = True):
    """
    Train DQN agent on Tower of Hanoi with GPU acceleration.
    
    Args:
        num_disks: Number of disks
        episodes: Number of training episodes
        target_update: Episodes between target network updates
        verbose: Whether to print progress
        
    Returns:
        Trained DQN agent
    """
    if not PYTORCH_AVAILABLE:
        raise ImportError("PyTorch is required for DQN. Install with: pip install torch")
    
    env = HanoiTower(num_disks)
    
    # State size: 2 values per disk (peg number, disk number)
    state_size = num_disks * 2
    action_size = 6
    
    agent = DQNAgent(state_size, action_size, 
                    learning_rate=0.001,
                    gamma=0.99,
                    epsilon=1.0,
                    epsilon_decay=0.9995,
                    batch_size=128)
    
    rewards_history = []
    moves_history = []
    loss_history = []
    success_rate = []
    
    start_time = time.time()
    
    for episode in range(episodes):
        state = env.reset()
        total_reward = 0
        done = False
        max_steps = 1000
        steps = 0
        episode_loss = []
        
        while not done and steps < max_steps:
            valid_actions = env.get_valid_actions()
            action = agent.get_action(state, valid_actions)
            next_state, reward, done, _ = env.step(action)
            
            # Store experience
            agent.remember(state, action, reward, next_state, done)
            
            # Train on batch (GPU parallel processing)
            loss = agent.train_step()
            if loss > 0:
                episode_loss.append(loss)
            
            state = next_state
            total_reward += reward
            steps += 1
        
        agent.decay_epsilon()
        rewards_history.append(total_reward)
        moves_history.append(env.moves)
        if episode_loss:
            loss_history.append(np.mean(episode_loss))
        
        # Update target network
        if (episode + 1) % target_update == 0:
            agent.update_target_network()
        
        # Calculate success rate
        if episode >= 99:
            recent_success = sum(1 for i in range(episode-99, episode+1) 
                               if rewards_history[i] > 0)
            success_rate.append(recent_success / 100)
        
        # Print progress
        if verbose and (episode + 1) % 1000 == 0:
            elapsed = time.time() - start_time
            avg_reward = np.mean(rewards_history[-1000:])
            avg_moves = np.mean(moves_history[-1000:])
            avg_loss = np.mean(loss_history[-1000:]) if loss_history else 0
            current_success = success_rate[-1] if success_rate else 0
            print(f"Episode {episode + 1}/{episodes} | Time: {elapsed:.1f}s | Device: {device}")
            print(f"  Avg Reward: {avg_reward:.2f}")
            print(f"  Avg Moves: {avg_moves:.2f}")
            print(f"  Avg Loss: {avg_loss:.4f}")
            print(f"  Success Rate: {current_success:.2%}")
            print(f"  Epsilon: {agent.epsilon:.4f}")
            print(f"  Memory Size: {len(agent.memory)}")
    
    training_time = time.time() - start_time
    
    if verbose:
        optimal_moves = 2**num_disks - 1
        print(f"\nTraining completed in {training_time:.2f} seconds ({training_time/60:.2f} minutes)")
        print(f"Optimal solution requires {optimal_moves} moves")
    
    return agent


def test_agent(agent: QLearningAgent, num_disks: int = 3, render: bool = True):
    """
    Test trained agent on Tower of Hanoi.
    
    Args:
        agent: Trained agent
        num_disks: Number of disks
        render: Whether to render the initial and final state
    """
    env = HanoiTower(num_disks)
    state = env.reset()
    
    if render:
        print("\n" + "="*40)
        print(f"Testing Agent on {num_disks}-disk Tower of Hanoi")
        print("="*40)
        env.render()
    
    done = False
    optimal_moves = 2**num_disks - 1
    max_steps = optimal_moves * 5  # Allow 5x optimal moves for poorly trained agents
    steps = 0
    
    while not done and steps < max_steps:
        valid_actions = env.get_valid_actions()
        action = agent.get_action(state, valid_actions, training=False)
        state, reward, done, _ = env.step(action)
        steps += 1
    
    if render:
        print("\n" + "="*40)
        print("Final state:")
        print("="*40)
        env.render()
    
    optimal_moves = 2**num_disks - 1
    print(f"\n{'='*40}")
    print(f"Solution found in {env.moves} moves")
    print(f"Optimal solution: {optimal_moves} moves")
    print(f"Efficiency: {optimal_moves/env.moves*100:.1f}%")
    print(f"{'='*40}\n")


